import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { Medal, UserPlus, User, Mail, Lock, Building, ArrowLeft } from 'lucide-react';
import { useNavigate, Link } from 'react-router-dom';

export const Register: React.FC = () => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    department: '',
    password: '',
    confirmPassword: ''
  });
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const { register, login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (formData.password !== formData.confirmPassword) {
      setError('Passwords do not match.');
      return;
    }

    if (formData.password.length < 6) {
      setError('Password must be at least 6 characters long.');
      return;
    }

    setIsLoading(true);

    try {
      await register({
        name: formData.name,
        email: formData.email,
        department: formData.department,
        password: formData.password
      });
      navigate('/');
    } catch (err: any) {
      let message = 'An error occurred during registration.';
      if (err.message) {
        message = err.message;
      } else if (err.code === 'auth/email-already-in-use') {
        message = 'Email is already in use. Please log in.';
      } else if (err.code === 'auth/weak-password') {
        message = 'Password is too weak.';
      } else if (err.code === 'auth/invalid-email') {
        message = 'Invalid email address.';
      }
      setError(message);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-indigo-100 to-white dark:from-gray-900 dark:to-gray-800 flex items-center justify-center p-4 transition-colors">
